import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import CaseRow from "../../components/cases/CaseRow.js";
import "../dashboard/Dashboard.css";
import api from "../../api.js";
import { Plus, Search } from "lucide-react";

export default function CasesPage() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));
  const isAdmin = user?.role_id === 1;
  const [allCases, setAllCases] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [priorityFilter, setPriorityFilter] = useState("All");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const getPriorityLabel = (num) => {
    switch (num) {
      case 3: return "High";
      case 2: return "Medium";
      case 1: return "Low";
      default: return "Unknown";
    }
  };

  // Status display label: backend stores "Close", display as "Closed"
  const getStatusLabel = (s) => (s === "Close" ? "Closed" : s);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError("");
      try {
        const res = await api.get("/cases");
        const data =
          res.data.message === "no assigned cases" ? [] : res.data;
        setAllCases(data);
        setFiltered(data);
      } catch (err) {
        if (err.response?.status === 401) {
          localStorage.removeItem("token");
          localStorage.removeItem("user");
          navigate("/", { replace: true });
        } else {
          setError("Failed to load cases");
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [navigate]);

  useEffect(() => {
    let result = allCases;
    if (search)
      result = result.filter(
        (c) =>
          c.title?.toLowerCase().includes(search.toLowerCase()) ||
          String(c.caseId).includes(search),
      );
    // statusFilter uses backend values ("Open","Close","Archived") but tab label shows "Closed"
    if (statusFilter !== "All")
      result = result.filter((c) => c.status === statusFilter);
    if (priorityFilter !== "All")
      result = result.filter(
        (c) => getPriorityLabel(c.priority) === priorityFilter,
      );
    setFiltered(result);
  }, [search, statusFilter, priorityFilter, allCases]);

  const statusTabs = [
    { label: "All", value: "All" },
    { label: "Open", value: "Open" },
    { label: "Closed", value: "Close" },
    { label: "Archived", value: "Archived" },
  ];

  const getTabCount = (value) => {
    if (value === "All") return allCases.length;
    return allCases.filter((c) => c.status === value).length;
  };

  return (
    <div className="dashboardMain">
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText">
            <span>LEGALLENS</span> Cases
          </h1>
          <p className="systemStatus">
            {isAdmin ? "All cases in the system" : "Your assigned cases"} •{" "}
            <span className="highlightText">{allCases.length} total</span>
          </p>
        </div>
        {isAdmin && (
          <button
            className="primaryActionBtn"
            style={{ width: "auto", padding: "0.75rem 1.5rem" }}
            onClick={() => navigate("/create-case")}
          >
            <Plus size={16} /> Create Case
          </button>
        )}
      </header>

      {/* Status Filter Tabs */}
      <div className="notifFilterTabs" style={{ marginBottom: "1.5rem" }}>
        {statusTabs.map(({ label, value }) => (
          <button
            key={value}
            className={`notifFilterTab ${statusFilter === value ? "notifFilterTabActive" : ""}`}
            onClick={() => setStatusFilter(value)}
          >
            {label} ({getTabCount(value)})
          </button>
        ))}
      </div>

      {/* Search + Priority Filter */}
      <div
        style={{
          display: "flex",
          gap: "1rem",
          marginBottom: "1.5rem",
          alignItems: "center",
        }}
      >
        <div className="membersSearch" style={{ flex: 1, maxWidth: 400 }}>
          <Search size={16} color="#475569" />
          <input
            type="text"
            placeholder="Search by title or case ID..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              background: "transparent",
              border: "none",
              outline: "none",
              color: "#fff",
              fontSize: "0.875rem",
              flex: 1,
            }}
          />
        </div>
        <select
          value={priorityFilter}
          onChange={(e) => setPriorityFilter(e.target.value)}
          style={{
            background: "#1e293b",
            border: "1px solid rgba(255,255,255,0.05)",
            color: "#fff",
            padding: "0.6rem 1rem",
            borderRadius: 8,
            fontSize: "0.875rem",
          }}
        >
          <option value="All">All Priorities</option>
          <option value="High">High</option>
          <option value="Medium">Medium</option>
          <option value="Low">Low</option>
        </select>
      </div>

      {/* Cases List */}
      <div className="formSectionCard">
        <div className="sectionHeader">
          <div className="indicatorDot" />
          <h2>CASE RECORDS</h2>
          <span
            style={{
              marginLeft: "auto",
              color: "#64748b",
              fontSize: "0.8rem",
            }}
          >
            {filtered.length} result{filtered.length !== 1 ? "s" : ""}
          </span>
        </div>
        <div className="casesListWrapper" style={{ padding: "0.5rem 0" }}>
          {loading ? (
            <div
              style={{ textAlign: "center", padding: "3rem", color: "#475569" }}
            >
              <div
                className="miniSpinner"
                style={{ margin: "0 auto 0.75rem" }}
              />
              Loading cases...
            </div>
          ) : error ? (
            <div
              style={{ textAlign: "center", padding: "3rem", color: "#f87171" }}
            >
              {error}
            </div>
          ) : filtered.length === 0 ? (
            <div
              style={{ textAlign: "center", padding: "3rem", color: "#475569" }}
            >
              <p>No cases found</p>
              {isAdmin && (
                <button
                  className="primaryActionBtn"
                  style={{ width: "auto", marginTop: "1rem" }}
                  onClick={() => navigate("/create-case")}
                >
                  <Plus size={16} /> Create First Case
                </button>
              )}
            </div>
          ) : (
            filtered.map((c) => (
              <CaseRow
                key={c.id}
                id={c.caseId}
                title={c.title}
                priority={getPriorityLabel(c.priority)}
                status={c.status}
              />
            ))
          )}
        </div>
      </div>
    </div>
  );
}
// Note: search from URL param is pre-applied in the URL init logic below
